<?php

declare(strict_types=1);

namespace Webconsulting\RecordsListTypes\Html;

use TYPO3\CMS\Core\Html\DefaultSanitizerBuilder;
use TYPO3\HtmlSanitizer\Behavior;
use TYPO3\HtmlSanitizer\Behavior\Attr;
use TYPO3\HtmlSanitizer\Behavior\Tag;

/**
 * Sanitizer preset for TYPO3 backend component/button fragments.
 *
 * The custom views render HTML generated by TYPO3 backend APIs
 * (DatabaseRecordList, ComponentFactory, icons, web components). This builder
 * extends TYPO3's default sanitizer with the backend-specific tags and
 * attributes required for those fragments.
 */
final class BackendFragmentSanitizerBuilder extends DefaultSanitizerBuilder
{
    protected function createBehavior(): Behavior
    {
        $behavior = parent::createBehavior();

        $commonBackendAttrs = [
            ...$this->globalAttrs,
            new Attr('popover'),
            new Attr('popovertarget'),
            new Attr('disabled'),
            new Attr('hidden'),
        ];

        $buttonAttrs = [
            ...$commonBackendAttrs,
            new Attr('type'),
            new Attr('name'),
            new Attr('value'),
        ];

        $anchorAttrs = [
            ...$commonBackendAttrs,
            $this->hrefAttr,
            ...$this->createAttrs('download', 'hreflang', 'ping', 'rel', 'referrerpolicy', 'target', 'type'),
        ];

        $inputAttrs = array_merge(
            $commonBackendAttrs,
            [
                new Attr('type'),
                new Attr('name'),
                new Attr('value'),
                new Attr('checked'),
            ],
        );
        $contextualTriggerAttrs = array_merge(
            $commonBackendAttrs,
            [
                new Attr('url'),
                new Attr('edit-url'),
            ],
        );
        $downloadButtonAttrs = array_merge(
            $commonBackendAttrs,
            [
                new Attr('url'),
                new Attr('subject'),
                new Attr('ok'),
                new Attr('close'),
            ],
        );
        $newPageWizardAttrs = array_merge(
            $commonBackendAttrs,
            [
                new Attr('configuration'),
            ],
        );
        $columnSelectorAttrs = array_merge(
            $commonBackendAttrs,
            [
                new Attr('url'),
                new Attr('table'),
                new Attr('identifier'),
                new Attr('preset'),
                new Attr('return-url'),
            ],
        );
        $clipboardPanelAttrs = array_merge(
            $commonBackendAttrs,
            [
                new Attr('return-url'),
            ],
        );

        return $behavior->withTags(
            (new Tag('button', Tag::ALLOW_CHILDREN))->addAttrs(...$buttonAttrs),
            (new Tag('input'))->addAttrs(...$inputAttrs),
            (new Tag('a', Tag::ALLOW_CHILDREN))->addAttrs(...$anchorAttrs),
            (new Tag('typo3-backend-contextual-record-edit-trigger', Tag::ALLOW_CHILDREN))->addAttrs(...$contextualTriggerAttrs),
            (new Tag('typo3-recordlist-record-download-button'))->addAttrs(...$downloadButtonAttrs),
            (new Tag('typo3-backend-new-page-wizard-button'))->addAttrs(...$newPageWizardAttrs),
            (new Tag('typo3-backend-column-selector-button'))->addAttrs(...$columnSelectorAttrs),
            (new Tag('typo3-backend-clipboard-panel'))->addAttrs(...$clipboardPanelAttrs),
        );
    }
}
